+// Added character-furniture interaction system with interaction poses and visual feedback
 /**
  * Professional pixel-art character & room renderer for KingdomOS.
  * Inspired by SkyOffice (Phaser/LimeZu) and Pixel Agents (Canvas 2D/sprite manifests).
  *
  * Key improvements over v1:
@@ -1731,6 +1732,113 @@ export { getCS, updateMovement };
+// ─── Interaction Poses ─────────────────────────────────────────────
+
+/**
+ * Returns a modified sprite array representing the character's interaction pose
+ * based on proximity to furniture type.
+ * This function returns a new sprite array with modifications to show sitting,
+ * standing at forge, or reading poses.
+ */
+export function getInteractionPose(type: CharacterType, baseSprite: string[], furnitureType: string): string[] {
+  // Defensive copy of base sprite
+  const sprite = baseSprite.map(line => line.split(''));
+
+  switch (furnitureType) {
+    case 'desk': // Sitting pose for desks (scribe, nobility, king)
+      // Lower legs tucked in (replace bottom rows with ' ' or sitting legs)
+      // Slightly lower torso to simulate sitting
+      for (let row = sprite.length - 3; row < sprite.length; row++) {
+        for (let col = 0; col < sprite[row].length; col++) {
+          if (sprite[row][col] === 'P' || sprite[row][col] === 'p') {
+            sprite[row][col] = ' '; // Remove standing legs
+          }
+          // Add sitting legs as 'l' (lowercase L) for visual difference
+          if (row === sprite.length - 2 && (col === 5 || col === 10)) {
+            sprite[row][col] = 'l';
+          }
+        }
+      }
+      // Lower torso slightly by shifting some pixels down
+      for (let row = sprite.length - 6; row < sprite.length - 3; row++) {
+        for (let col = 0; col < sprite[row].length; col++) {
+          if (sprite[row][col] === 'P') {
+            sprite[row + 2][col] = 'P';
+            sprite[row][col] = ' ';
+          }
+        }
+      }
+      break;
+
+    case 'forge': // Standing at forge pose for blacksmith
+      // Add hammer raised pose: shift 'M' pixels up and right slightly
+      for (let row = 0; row < sprite.length; row++) {
+        for (let col = sprite[row].length - 2; col >= 0; col--) {
+          if (sprite[row][col] === 'M') {
+            sprite[row][col] = ' ';
+            if (row > 0 && col < sprite[row].length - 1) {
+              sprite[row - 1][col + 1] = 'M';
+            }
+          }
+        }
+      }
+      break;
+
+    case 'lectern': // Reading pose for scribes or nobles at lecterns
+      // Tilt head forward by replacing some head pixels with '0' (closed eyes)
+      for (let row = 2; row < 5; row++) {
+        for (let col = 4; col < 12; col++) {
+          if (sprite[row][col] === 'O') {
+            sprite[row][col] = '0';
+          }
+        }
+      }
+      // Add book in front by adding 'B' pixels on torso area
+      const torsoRow = sprite.length - 8;
+      for (let col = 5; col < 11; col++) {
+        if (sprite[torsoRow][col] === 'P' || sprite[torsoRow][col] === 'p') {
+          sprite[torsoRow][col] = 'B';
+        }
+      }
+      break;
+
+    default:
+      // No modification
+      break;
+  }
+
+  // Convert back to string array
+  return sprite.map(line => line.join(''));
+}
+
+/**
+ * Checks if character is near furniture and returns the furniture type if so.
+ * For simplicity, we assume furniture positions are fixed per room type.
+ * Returns null if no furniture nearby.
+ */
+export function getNearbyFurniture(characterX: number, characterY: number, roomType: string): string | null {
+  // Define furniture positions per room (normalized coordinates)
+  const furniturePositions: Record<string, { x: number; y: number; type: string }[]> = {
+    throneRoom: [
+      { x: 0.4, y: 0.5, type: 'desk' }, // planning table
+    ],
+    armory: [
+      { x: 0.25, y: 0.3, type: 'forge' }, // workbench area
+    ],
+    alchemyLab: [
+      { x: 0.6, y: 0.6, type: 'lectern' }, // scribe desk
+    ],
+    scriptorium: [
+      { x: 0.6, y: 0.6, type: 'desk' }, // writing desk
+    ],
+    blacksmith: [
+      { x: 0.5, y: 0.5, type: 'forge' },
+    ],
+    scribe: [
+      { x: 0.6, y: 0.6, type: 'desk' },
+    ],
+    nobility: [
+      { x: 0.4, y: 0.5, type: 'desk' },
+    ],
+    king: [
+      { x: 0.4, y: 0.5, type: 'desk' },
+    ],
+  };
+
+  const threshold = 0.08; // proximity threshold
+  const furnitures = furniturePositions[roomType] || [];
+  for (const f of furnitures) {
+    const dx = characterX - f.x;
+    const dy = characterY - f.y;
+    if (dx * dx + dy * dy < threshold * threshold) {
+      return f.type;
+    }
+  }
+  return null;
+}
+
+/**
+ * Draws visual feedback indicator near furniture when character is close.
+ * Draws a glowing circle or highlight around the furniture position.
+ */
+export function drawFurnitureIndicator(ctx: CanvasRenderingContext2D, roomType: string, x: number, y: number, w: number, h: number, furnitureType: string) {
+  const furniturePositions: Record<string, { x: number; y: number }[]> = {
+    throneRoom: [{ x: 0.4, y: 0.5 }],
+    armory: [{ x: 0.25, y: 0.3 }],
+    alchemyLab: [{ x: 0.6, y: 0.6 }],
+    scriptorium: [{ x: 0.6, y: 0.6 }],
+    blacksmith: [{ x: 0.5, y: 0.5 }],
+    scribe: [{ x: 0.6, y: 0.6 }],
+    nobility: [{ x: 0.4, y: 0.5 }],
+    king: [{ x: 0.4, y: 0.5 }],
+  };
+  const positions = furniturePositions[roomType];
+  if (!positions) return;
+  for (const pos of positions) {
+    const fx = x + pos.x * w;
+    const fy = y + pos.y * h;
+    const radius = Math.min(w, h) * 0.05;
+    const gradient = ctx.createRadialGradient(fx, fy, radius * 0.5, fx, fy, radius);
+    gradient.addColorStop(0, 'rgba(255, 215, 0, 0.6)');
+    gradient.addColorStop(1, 'rgba(255, 215, 0, 0)');
+    ctx.fillStyle = gradient;
+    ctx.beginPath();
+    ctx.arc(fx, fy, radius, 0, Math.PI * 2);
+    ctx.fill();
+  }
+}
+
+// ─── Modified drawCharacter to use interaction poses and indicators ───────────────────────
+
+export function drawCharacterWithInteraction(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  state: AnimState,
+  x: number, y: number, s: number, frame: number,
+  roomType: string,
+  agentId?: string,
+  currentJob?: string | null,
+) {
+  const id = agentId ?? `${type}-${Math.round(x)}`;
+  const baseSprite = SPRITE_MAP[type];
+  const palette = PALETTE_MAP[type];
+  const cs = getCS(id, x, y);
+  const bob = state === 'idle' ? Math.sin(frame * 0.05) * 1.2 : state === 'working' ? Math.sin(frame * 0.1) * 0.8 : 0;
+  const drawY = cs.y + bob;
+  const flipH = cs.dir === 'left';
+
+  // Determine if near furniture and get furniture type
+  const furnitureType = getNearbyFurniture(cs.x / 100, cs.y / 100, roomType);
+
+  // Choose sprite: interaction pose or base sprite
+  let spriteToDraw = baseSprite;
+  if (furnitureType) {
+    spriteToDraw = getInteractionPose(type, baseSprite, furnitureType);
+  }
+
+  // Drop shadow
+  ctx.fillStyle = 'rgba(0,0,0,0.3)';
+  ctx.beginPath();
+  ctx.ellipse(cs.x + 8 * s, drawY + spriteToDraw.length * s + 2, 7 * s, 2 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  drawSpriteDef(ctx, spriteToDraw, palette, cs.x, drawY, s, flipH);
+
+  // Walking leg overlay (skip if interaction pose)
+  if (cs.moving && !furnitureType) {
+    const lp = Math.sin(cs.wf * 0.3) * 2 * s;
+    ctx.fillStyle = palette.B;
+    ctx.fillRect(cs.x + 4 * s, drawY + (spriteToDraw.length - 3) * s + lp, 3 * s, 2 * s);
+    ctx.fillRect(cs.x + 9 * s, drawY + (spriteToDraw.length - 3) * s - lp, 3 * s, 2 * s);
+  }
+
+  drawStatusEffect(ctx, state, cs.x, drawY, s, frame);
+  if (agentId) {
+    updateBubble(id, state, currentJob ?? null, frame);
+    drawBubble(ctx, id, cs.x + 8 * s, drawY - 4);
+  }
+
+  // Draw visual feedback indicator near furniture if close
+  if (furnitureType) {
+    drawFurnitureIndicator(ctx, roomType, 0, 0, 100, 100, furnitureType);
+  }
+}
+
